import { Component, computed, inject } from '@angular/core';
import { Router, RouterLink } from '@angular/router';
import { BaseChartDirective, provideCharts, withDefaultRegisterables } from 'ng2-charts';
import { MatIconModule } from '@angular/material/icon';
import { CurrencyFormatPipe } from '../currency-format.pipe';
import { ApiService } from '../api.service';
import { toSignal } from '@angular/core/rxjs-interop';
import { DisasterOverview, DisasterRecoveryRatio } from '@shared/interfaces';

export interface ChartDataset {
  label: string;
  data: number[];
}

type AgencyWithTotal = { id: number; name: string; totalCents: number };

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [BaseChartDirective, CurrencyFormatPipe, RouterLink, MatIconModule],
  providers: [provideCharts(withDefaultRegisterables())],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.scss',
})
export class DashboardComponent {
  private readonly api = inject(ApiService);
  private readonly router = inject(Router);

  private static readonly TOP_N = 5;

  private readonly agencies = toSignal(this.api.getAgencies(), {
    initialValue: [] as AgencyWithTotal[],
  });
  private readonly overview = toSignal(this.api.getDisasterOverview({}), {
    initialValue: [] as DisasterOverview[],
  });
  private readonly ratios = toSignal(this.api.getDisasterRecoveryRatios({}), {
    initialValue: [] as DisasterRecoveryRatio[],
  });
  readonly lastSync = toSignal(this.api.getLastSync(), {
    initialValue: null as string | null,
  });

  readonly disasterTotal = computed(() =>
    this.overview().reduce((sum, r) => sum + r.totalObligated, 0),
  );

  readonly totalObligated = computed(() =>
    this.agencies().reduce((sum, a) => sum + a.totalCents, 0) + this.disasterTotal(),
  );

  readonly largestAgency = computed<{ name: string; totalCents: number } | null>(() => {
    const list = this.agencies();
    if (list.length === 0) return null;
    const largest = list.reduce<{ name: string; totalCents: number } | null>(
      (best, a) => (!best || a.totalCents > best.totalCents ? a : best),
      null,
    );
    return largest ? { name: largest.name, totalCents: largest.totalCents } : null;
  });

  readonly coverageGapCount = computed(() => {
    const gapStates = new Set(
      this.ratios().filter(r => r.recoveryRatio < 0.5).map(r => r.stateCode),
    );
    return gapStates.size;
  });

  private readonly topAgencies = computed(() => {
    const withData = this.agencies().filter(a => a.totalCents > 0);
    return [...withData]
      .sort((a, b) => b.totalCents - a.totalCents)
      .slice(0, DashboardComponent.TOP_N);
  });

  readonly chartLabels = computed(() =>
    this.topAgencies().map(a => a.name).concat(['Disaster Spending']),
  );

  readonly chartDatasets = computed<ChartDataset[]>(() => [
    {
      label: 'Obligated (cents)',
      data: this.topAgencies().map(a => a.totalCents).concat([this.disasterTotal()]),
    },
  ]);

  readonly chartAgencyIds = computed(() => this.topAgencies().map(a => a.id));

  onChartClick(event: any): void {
    const clicked = event.active[0];
    if (!clicked) return;
    const index = clicked.index;
    if (index < this.chartAgencyIds().length) {
      this.router.navigate(['/agencies', this.chartAgencyIds()[index]]);
    }
  }

  onNavClick(route: string, event: Event): void {
    event.preventDefault();
    this.router.navigate([route]);
  }
}

import { ComponentFixture, TestBed, fakeAsync, tick } from '@angular/core/testing';
import { Router, RouterLink, ActivatedRoute } from '@angular/router';
import { MatIconModule } from '@angular/material/icon';
import { of, Subject } from 'rxjs';
import { provideCharts, withDefaultRegisterables } from 'ng2-charts';

import { DashboardComponent } from './dashboard.component';
import { ApiService } from '../api.service';
import { CurrencyFormatPipe } from '../currency-format.pipe';

describe('DashboardComponent', () => {
  let routerSpy: {
    navigate: jest.Mock;
    createUrlTree: jest.Mock;
    serializeUrl: jest.Mock;
    navigateEnd: jest.Mock;
    events: any;
  };
  let apiSpy: {
    getAgencies: jest.Mock;
    getDisasterOverview: jest.Mock;
    getDisasterRecoveryRatios: jest.Mock;
    getLastSync: jest.Mock;
  };

  beforeEach(() => {
    const events$ = new (require('rxjs')).Subject<any>();
    routerSpy = {
      navigate: jest.fn(),
      createUrlTree: jest.fn((links: string[]) => links.length > 0 ? links[0] : '/'),
      serializeUrl: jest.fn((url: string) => ({ toString: () => url })),
      navigateEnd: jest.fn(),
      events: events$,
    };
    apiSpy = {
      getAgencies: jest.fn().mockReturnValue(of([])),
      getDisasterOverview: jest.fn().mockReturnValue(of([])),
      getDisasterRecoveryRatios: jest.fn().mockReturnValue(of([])),
      getLastSync: jest.fn().mockReturnValue(of(null)),
    };

    TestBed.configureTestingModule({
      imports: [DashboardComponent, CurrencyFormatPipe, RouterLink, MatIconModule],
      providers: [
        { provide: Router, useValue: routerSpy },
        { provide: ApiService, useValue: apiSpy },
        { provide: ActivatedRoute, useValue: { snapshot: { data: {} } } },
        provideCharts(withDefaultRegisterables()),
      ],
    });
  });

  interface CardTestCase {
    name: string;
    agencies: Array<{ id: number; name: string; totalCents: number }>;
    ratios: Array<{ stateCode: string; recoveryRatio: number }>;
    expectedTotal: number;
    expectedLargest: { name: string; totalCents: number } | null;
    expectedGapCount: number;
  }

  const testTable: CardTestCase[] = [
    {
      name: 'computes total obligated across all agencies',
      agencies: [
        { id: 1, name: 'Agency A', totalCents: 100000 },
        { id: 2, name: 'Agency B', totalCents: 200000 },
        { id: 3, name: 'Agency C', totalCents: 300000 },
      ],
      ratios: [],
      expectedTotal: 600000,
      expectedLargest: { name: 'Agency C', totalCents: 300000 },
      expectedGapCount: 0,
    },
    {
      name: 'identifies largest agency by highest totalCents',
      agencies: [
        { id: 1, name: 'Small', totalCents: 50000 },
        { id: 2, name: 'Medium', totalCents: 150000 },
        { id: 3, name: 'Large', totalCents: 500000 },
      ],
      ratios: [],
      expectedTotal: 700000,
      expectedLargest: { name: 'Large', totalCents: 500000 },
      expectedGapCount: 0,
    },
    {
      name: 'counts distinct states with coverage gap ratio below 0.5',
      agencies: [],
      ratios: [
        { stateCode: '06', recoveryRatio: 0.3 },
        { stateCode: '12', recoveryRatio: 0.8 },
        { stateCode: '48', recoveryRatio: 0.2 },
        { stateCode: '06', recoveryRatio: 0.4 },
        { stateCode: '36', recoveryRatio: 1.5 },
      ],
      expectedTotal: 0,
      expectedLargest: null,
      expectedGapCount: 2,
    },
    {
      name: 'handles empty agencies and ratios gracefully',
      agencies: [],
      ratios: [],
      expectedTotal: 0,
      expectedLargest: null,
      expectedGapCount: 0,
    },
  ];

  it.each(testTable)('$name', ({ agencies, ratios, expectedTotal, expectedLargest, expectedGapCount }) => {
    apiSpy.getAgencies.mockReturnValue(of(agencies));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of(ratios));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    expect(component.totalObligated()).toBe(expectedTotal);
    expect(component.largestAgency()).toEqual(expectedLargest);
    expect(component.coverageGapCount()).toBe(expectedGapCount);
  });

  it('groups 6 agencies into top-5 bars plus Disaster Spending bar', () => {
    apiSpy.getAgencies.mockReturnValue(of([
      { id: 1, name: 'Agency A', totalCents: 500000 },
      { id: 2, name: 'Agency B', totalCents: 300000 },
      { id: 3, name: 'Agency C', totalCents: 200000 },
      { id: 4, name: 'Agency D', totalCents: 100000 },
      { id: 5, name: 'Agency E', totalCents: 50000 },
      { id: 6, name: 'Agency F', totalCents: 10000 },
    ]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    expect(component.chartLabels()).toEqual([
      'Agency A', 'Agency B', 'Agency C', 'Agency D', 'Agency E', 'Disaster Spending',
    ]);
    expect(component.chartDatasets()[0].data).toEqual([500000, 300000, 200000, 100000, 50000, 0]);
    expect(component.chartAgencyIds()).toEqual([1, 2, 3, 4, 5]);
    expect(component.chartLabels().length).toBe(6);
  });

  it('shows single Disaster Spending bar when all agencies have zero spending', () => {
    apiSpy.getAgencies.mockReturnValue(of([
      { id: 1, name: 'Agency A', totalCents: 0 },
      { id: 2, name: 'Agency B', totalCents: 0 },
      { id: 3, name: 'Agency C', totalCents: 0 },
    ]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    expect(component.chartLabels()).toEqual(['Disaster Spending']);
    expect(component.chartDatasets()[0].data).toEqual([0]);
    expect(component.chartAgencyIds()).toEqual([]);
    expect(component.chartLabels().length).toBe(1);
  });

  it('shows fewer bars than TOP_N plus Disaster Spending when fewer agencies have data', () => {
    apiSpy.getAgencies.mockReturnValue(of([
      { id: 1, name: 'Agency A', totalCents: 500000 },
      { id: 2, name: 'Agency B', totalCents: 300000 },
    ]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    expect(component.chartLabels()).toEqual(['Agency A', 'Agency B', 'Disaster Spending']);
    expect(component.chartDatasets()[0].data).toEqual([500000, 300000, 0]);
    expect(component.chartAgencyIds()).toEqual([1, 2]);
    expect(component.chartLabels().length).toBe(3);
  });

  it('navigates to top bar agency on chart click', () => {
    apiSpy.getAgencies.mockReturnValue(of([
      { id: 1, name: 'Agency A', totalCents: 500000 },
      { id: 2, name: 'Agency B', totalCents: 300000 },
      { id: 3, name: 'Agency C', totalCents: 200000 },
      { id: 4, name: 'Agency D', totalCents: 100000 },
      { id: 5, name: 'Agency E', totalCents: 50000 },
      { id: 6, name: 'Agency F', totalCents: 10000 },
    ]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    component.onChartClick({ active: [{ datasetIndex: 0, index: 0 }] });
    expect(routerSpy.navigate).toHaveBeenCalledWith(['/agencies', 1]);

    component.onChartClick({ active: [{ datasetIndex: 0, index: 3 }] });
    expect(routerSpy.navigate).toHaveBeenCalledWith(['/agencies', 4]);
  });

  it('does not navigate when Disaster Spending bar is clicked', () => {
    apiSpy.getAgencies.mockReturnValue(of([
      { id: 1, name: 'Agency A', totalCents: 500000 },
      { id: 2, name: 'Agency B', totalCents: 300000 },
    ]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    component.onChartClick({ active: [{ datasetIndex: 0, index: 2 }] });
    expect(routerSpy.navigate).not.toHaveBeenCalled();
  });

  it('does nothing on chart click with no active bar', () => {
    apiSpy.getAgencies.mockReturnValue(of([]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    component.onChartClick({ active: [] });
    expect(routerSpy.navigate).not.toHaveBeenCalled();
  });

  it('fetches agencies, overview, ratios, and last sync on construction', () => {
    apiSpy.getAgencies.mockReturnValue(of([]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));
    apiSpy.getLastSync.mockReturnValue(of('2024-01-15T10:00:00Z'));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    expect(apiSpy.getAgencies).toHaveBeenCalledTimes(1);
    expect(apiSpy.getDisasterOverview).toHaveBeenCalledTimes(1);
    expect(apiSpy.getDisasterRecoveryRatios).toHaveBeenCalledTimes(1);
    expect(apiSpy.getLastSync).toHaveBeenCalledTimes(1);
    expect(component.lastSync()).toBe('2024-01-15T10:00:00Z');
  });

  it('renders 3 nav cards with correct routerLink targets', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const cards = fixture.nativeElement.querySelectorAll('.card-body');
    expect(cards.length).toBe(3);

    const links = fixture.nativeElement.querySelectorAll('a[href]');
    expect(links.length).toBe(3);

    const routes = Array.from(links as NodeListOf<Element>).map(l => l.getAttribute('href'));
    expect(routes).toContain('/geography');
    expect(routes).toContain('/agencies');
    expect(routes).toContain('/disaster');
  });

  it('navigates to /geography when geography card is clicked', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const link = fixture.nativeElement.querySelector('.nav-card:nth-child(1)');
    link.dispatchEvent(new Event('click', { bubbles: true }));
    expect(routerSpy.navigate).toHaveBeenCalledWith(['/geography']);
  });

  it('navigates to /agencies when agencies card is clicked', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const link = fixture.nativeElement.querySelector('.nav-card:nth-child(2)');
    link.dispatchEvent(new Event('click', { bubbles: true }));
    expect(routerSpy.navigate).toHaveBeenCalledWith(['/agencies']);
  });

  it('navigates to /disaster when disaster card is clicked', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const link = fixture.nativeElement.querySelector('.nav-card:nth-child(3)');
    link.dispatchEvent(new Event('click', { bubbles: true }));
    expect(routerSpy.navigate).toHaveBeenCalledWith(['/disaster']);
  });

  it('each nav card has title, description, and icon', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const cards = fixture.nativeElement.querySelectorAll('.card-body');
    expect(cards.length).toBe(3);

    for (const card of cards) {
      expect(card.querySelector('h2')).toBeTruthy();
      expect(card.querySelector('p')).toBeTruthy();
      expect(card.parentElement.querySelector('mat-icon')).toBeTruthy();
    }
  });

  it('renders the about paragraph between h1 and nav-cards', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const h1 = fixture.nativeElement.querySelector('h1');
    expect(h1).toBeTruthy();

    const about = fixture.nativeElement.querySelector('.about');
    expect(about).toBeTruthy();
    expect(about.textContent).toContain('USASpending.gov');
    expect(about.textContent).toContain('OpenFEMA');
    expect(about.textContent).toContain('navigation cards');
    expect(about.textContent).toContain('summary cards');
    expect(about.textContent).toContain('agency chart');

    const navCards = fixture.nativeElement.querySelector('.nav-cards');
    expect(navCards).toBeTruthy();

    const h1Index = Array.from(fixture.nativeElement.childNodes).indexOf(h1);
    const aboutIndex = Array.from(fixture.nativeElement.childNodes).indexOf(about);
    const navCardsIndex = Array.from(fixture.nativeElement.childNodes).indexOf(navCards);
    expect(aboutIndex).toBeGreaterThan(h1Index);
    expect(aboutIndex).toBeLessThan(navCardsIndex);
  });

  it('page load completes in under 2 seconds', fakeAsync(() => {
    apiSpy.getAgencies.mockReturnValue(of([]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));
    apiSpy.getLastSync.mockReturnValue(of(null));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    const start = Date.now();
    fixture.detectChanges();
    tick(100);
    const elapsed = Date.now() - start;

    expect(elapsed).toBeLessThan(2000);
  }));
});

import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { MatTabsModule, MatTabChangeEvent } from '@angular/material/tabs';
import { MatSelectModule } from '@angular/material/select';
import { MatCardModule } from '@angular/material/card';
import { MatTableModule } from '@angular/material/table';
import { MatPaginatorModule } from '@angular/material/paginator';
import { BarChartComponent } from '../bar-chart/bar-chart.component';
import { toSignal, toObservable } from '@angular/core/rxjs-interop';
import { ApiService } from '../api.service';
import { CurrencyFormatPipe } from '../currency-format.pipe';
import { DisasterOverview, DisasterFundingRecord, DisasterRecoveryRatio } from '@shared/interfaces';
import { switchMap } from 'rxjs';

@Component({
  selector: 'app-disaster-lens',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    MatTabsModule,
    MatSelectModule,
    MatCardModule,
    MatTableModule,
    MatPaginatorModule,
    BarChartComponent,
    CurrencyFormatPipe,
  ],
  templateUrl: './disaster-lens.component.html',
  styleUrl: './disaster-lens.component.scss',
})
export class DisasterLensComponent {
  private readonly api = inject(ApiService);

  readonly currentTab = signal('COVID-19');
  readonly tabIndex = signal(0);
  readonly selectedFiscalYear = signal<number | null>(null);

  readonly defGroups = ['COVID-19', 'Infrastructure'];
  readonly fiscalYears = (() => {
    const now = new Date();
    const currentFy = now.getMonth() < 9 ? now.getFullYear() : now.getFullYear() + 1;
    const years: number[] = [];
    for (let fy = currentFy; fy >= 2018; fy--) years.push(fy);
    return years;
  })();
  readonly displayedColumns: string[] = ['state', 'declarations', 'fema', 'fedDef', 'dominantIncident'];

  readonly pageIndex = signal(0);
  readonly pageSize = signal(15);

  private readonly overview$ = toSignal(
    toObservable(this.currentTab).pipe(
      switchMap(tab => this.api.getDisasterOverview({ defGroup: tab })),
    ),
    { initialValue: [] as DisasterOverview[] },
  );

  private readonly statesParams = computed(() => {
    const params: { defGroup: string; fiscalYear?: number } = { defGroup: this.currentTab() };
    if (this.selectedFiscalYear() !== null) params.fiscalYear = this.selectedFiscalYear()!;
    return params;
  });

  private readonly states$ = toSignal(
    toObservable(this.statesParams).pipe(switchMap(p => this.api.getDisasterStates(p))),
    { initialValue: [] as DisasterFundingRecord[] },
  );

  private readonly ratiosParams = computed(() => {
    const params: { fiscalYear?: number } = {};
    if (this.selectedFiscalYear() !== null) params.fiscalYear = this.selectedFiscalYear()!;
    return params;
  });

  private readonly ratios$ = toSignal(
    toObservable(this.ratiosParams).pipe(switchMap(p => this.api.getDisasterRecoveryRatios(p))),
    { initialValue: [] as DisasterRecoveryRatio[] },
  );

  readonly totalObligated = computed(() => {
    const current = this.overview$()[0];
    return current ? current.totalObligated : 0;
  });

  readonly highestPerCapitaState = computed(() => {
    const current = this.overview$()[0];
    return current ? current.highestPerCapitaState : '';
  });

  readonly stateCount = computed(() => this.states$().length);

  private readonly top15 = computed(() => DisasterLensComponent.pickTop15(this.states$()));
  readonly top15Labels = computed(() => this.top15().map(s => s.stateName));
  readonly top15Datasets = computed(() => this.top15().map(s => s.obligatedAmount));

  readonly sortedRatios = computed(() =>
    DisasterLensComponent.aggregateByState(this.ratios$()).sort(
      (a, b) => b.fedSpendingObligated - a.fedSpendingObligated,
    ),
  );

  readonly pagedRatios = computed(() => {
    const start = this.pageIndex() * this.pageSize();
    return this.sortedRatios().slice(start, start + this.pageSize());
  });

  onTabChange(event: MatTabChangeEvent): void {
    this.currentTab.set(this.defGroups[event.index]);
    this.tabIndex.set(event.index);
  }

  onFiscalYearChange(value: number | null): void {
    this.selectedFiscalYear.set(value);
  }

  onPage(event: { pageIndex: number; pageSize: number }): void {
    this.pageIndex.set(event.pageIndex);
    this.pageSize.set(event.pageSize);
  }

  static pickTop15(states: DisasterFundingRecord[]): DisasterFundingRecord[] {
    return [...states]
      .sort((a, b) => b.obligatedAmount - a.obligatedAmount)
      .slice(0, 15);
  }

  static aggregateByState(ratios: DisasterRecoveryRatio[]): DisasterRecoveryRatio[] {
    const byState = new Map<string, DisasterRecoveryRatio>();
    for (const r of ratios) {
      const existing = byState.get(r.stateCode);
      if (existing) {
        existing.femaObligated += r.femaObligated;
        existing.declarationCount += r.declarationCount;
      } else {
        byState.set(r.stateCode, { ...r });
      }
    }
    return [...byState.values()];
  }
}

import { ComponentFixture, TestBed } from '@angular/core/testing';
import { provideHttpClient } from '@angular/common/http';
import { of } from 'rxjs';
import { DisasterLensComponent } from './disaster-lens.component';
import { ApiService } from '../api.service';
import { CurrencyFormatPipe } from '../currency-format.pipe';
import {
  DisasterFundingRecord,
  DisasterOverview,
  DisasterRecoveryRatio,
} from '@shared/interfaces';

describe('DisasterLensComponent', () => {
  let fixture: ComponentFixture<DisasterLensComponent>;
  let apiSpy: {
    getDisasterOverview: jest.Mock;
    getDisasterStates: jest.Mock;
    getDisasterRecoveryRatios: jest.Mock;
  };

  beforeEach(async () => {
    apiSpy = {
      getDisasterOverview: jest.fn(),
      getDisasterStates: jest.fn(),
      getDisasterRecoveryRatios: jest.fn(),
    };

    await TestBed.configureTestingModule({
      imports: [
        DisasterLensComponent,
        CurrencyFormatPipe,
      ],
      providers: [
        provideHttpClient(),
        { provide: ApiService, useValue: apiSpy },
      ],
    }).compileComponents();
  });

  afterEach(() => {
    jest.restoreAllMocks();
  });

  function mount(overview: DisasterOverview[], states: DisasterFundingRecord[], ratios: DisasterRecoveryRatio[], tab = 'COVID-19') {
    apiSpy.getDisasterOverview.mockImplementation((params: { defGroup: string }) =>
      of(overview.filter(o => o.defGroup === params.defGroup)),
    );
    apiSpy.getDisasterStates.mockReturnValue(of(states));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of(ratios));

    fixture = TestBed.createComponent(DisasterLensComponent);
    const component = fixture.componentInstance;
    component.currentTab.set(tab);
    fixture.detectChanges();
    return component;
  }

  interface CardTestCase {
    name: string;
    defGroup?: string;
    overview: DisasterOverview[];
    states: DisasterFundingRecord[];
    ratios: DisasterRecoveryRatio[];
    expectedTotalObligated: number;
    expectedStateCount: number;
    expectedHighestPerCapitaState: string;
  }

  const testTable: CardTestCase[] = [
    {
      name: 'resolves overview for matching defGroup from server',
      defGroup: 'COVID-19',
      overview: [
        {
          defGroup: 'COVID-19',
          totalObligated: 500000,
          totalAwardCount: 100,
          stateCount: 2,
          highestPerCapitaState: 'CA',
          highestPerCapita: 100000,
          coverageGapCount: 0,
        },
      ],
      states: [
        {
          id: 1, stateCode: 'CA', stateName: 'California',
          obligatedAmount: 300000, awardCount: 50,
          perCapita: 0, population: 0, defGroup: 'COVID-19', defCodes: '',
        },
        {
